Use this only for logic that cannot be expressed through existing tools or vectorized operations. Use to_array() for cell-level logic. library(whiteboxworkflows) r <- wbw_read_raster('dem.tif')
a <- r$to_array()
meta <- r$metadata() nr <- dim(a)[1]
nc <- dim(a)[2] for (row in seq_len(nr)) { for (col in seq_len(nc)) { z <- a[row, col] if (!is.na(z) && z != meta$nodata) { if (z < 0) { a[row, col] <- 0 } } }
}

