a <- r$to_array() # If array is [rows, cols, bands], loop accordingly.
d <- dim(a)
if (length(d) == 3) { nr <- d[1] nc <- d[2] nb <- d[3] for (b in seq_len(nb)) { for (row in seq_len(nr)) { for (col in seq_len(nc)) { v <- a[row, col, b] if (!is.na(v) && v < 0) { a[row, col, b] <- 0 } } } }
} wbw_array_to_raster(a, r, output_path = 'multiband_clamped.tif')

