Use session execution and topology/geometry tool IDs through category discovery. library(whiteboxworkflows) s <- wbw_session() # Discover likely topology-related tools
hits <- wbw_search_tools('topology')
print(hits) # Inspect a specific candidate tool
if (length(hits) > 0) { first_hit <- hits[[1]] tool_id <- if (is.list(first_hit) && !is.null(first_hit$tool_id)) first_hit$tool_id else as.character(first_hit) print(wbw_describe_tool(tool_id))
} Use this pattern when topology checks are part of larger, file-based vector pipelines that should remain in Whitebox tooling end to end.
